"use client";

import { useState } from "react";
import CountUp from "react-countup";
import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay } from "swiper/modules";
import "swiper/css";
import VideoModal from "@/components/ui/VideoModal";
import { PlayButton } from "@/components/ui/PlayButton";
import { PlayButton } from "@/components/ui/PlayButton";

export default function Banner() {
  const [open, setOpen] = useState(false);

  const sliderImages = [
    "https://images.unsplash.com/photo-1557804506-669a67965ba0?q=80&w=1200&auto=format&fit=crop",
    "https://images.unsplash.com/photo-1521737604893-d14cc237f11d?q=80&w=1200&auto=format&fit=crop",
    "https://images.unsplash.com/photo-1492724441997-5dc865305da7?q=80&w=1200&auto=format&fit=crop",
    "https://images.unsplash.com/photo-1551434678-e076c223a692?q=80&w=1200&auto=format&fit=crop",
  ];

  return (
    <>
      <section className="relative z-10 text-white text-center overflow-hidden
        pt-[clamp(120px,10.51vw,200px)]
        pb-[clamp(0px,26.96vw,513px)]
        px-[15px]
        bg-gradient-to-r from-indigo-600 to-purple-700">

        {/* Background SVG Blend */}
        <div className="absolute inset-0 -z-10 mix-blend-multiply 
          bg-[url('/assets/img/banner-bg-shape.svg')] bg-cover bg-center" />

        {/* VECTORS */}
        <img
          src="/assets/img/banner-vector-2.svg"
          className="absolute left-[clamp(350px,37.62vw,716px)] 
          bottom-[clamp(68px,5.68vw,108px)]
          max-w-[clamp(88px,9.35vw,178px)]
          hidden lg:block"
          alt=""
        />

        <img
          src="/assets/img/banner-vector-3.svg"
          className="absolute right-[clamp(25px,2.63vw,50px)] 
          bottom-[clamp(15px,12.09vw,230px)]
          max-w-[clamp(295px,31vw,590px)]
          hidden lg:block"
          alt=""
        />

        {/* TEXT */}
        <div className="relative z-10">

          <div className="inline-flex items-center border border-white/20 rounded-full
            px-[clamp(13px,0.84vw,16px)]
            py-[clamp(6px,0.47vw,9px)]
            font-bold mb-[clamp(7px,0.63vw,12px)]">
            Empowering Your Business with Data-Driven Marketing
          </div>

          <h1 className="font-extrabold
            text-[clamp(25px,3.68vw,70px)]
            max-w-[clamp(300px,55.6vw,1058px)]
            mx-auto
            mb-[clamp(8px,0.84vw,16px)]">
            Empowering Your Business with Data-Driven Marketing
          </h1>

          <a
            href="/services"
            className="inline-flex items-center gap-[clamp(5px,0.53vw,10px)]
            bg-white text-indigo-600
            rounded-full
            px-[clamp(15px,1.05vw,20px)]
            h-[clamp(36px,2.42vw,46px)]
            font-bold
            hover:bg-indigo-600 hover:text-white transition">
            Our Services ↗
          </a>
        </div>

        {/* ================= SLIDERS ================= */}

        <div className="absolute inset-0 pointer-events-none">

          {/* Slider 1 */}
          <Slider
            images={sliderImages}
            className="absolute left-0 bottom-0
              w-[clamp(160px,34.68vw,660px)]"
            clipPath={`polygon(35.014% 0%,98.457% 0%,99.575% 3.239%,30.829% 99.274%,-30.73% 96.709%,33.865% 0.674%,35.014% 0%)`}
          />

          {/* Slider 2 */}
          <Slider
            images={sliderImages}
            className="absolute bottom-0
              left-[clamp(137px,12.45vw,237px)]
              w-[clamp(160px,36.57vw,696px)]"
            clipPath={`polygon(44.741% 0%,98.445% 0%,99.534% 4.75%,58.979% 98.859%,0.487% 95.039%,43.682% 0.93%,44.741% 0%)`}
          />

          {/* Slider 3 */}
          <Slider
            images={sliderImages}
            className="absolute
              bottom-[clamp(78px,8.3vw,158px)]
              right-[clamp(180px,20.23vw,385px)]
              w-[clamp(0px,38.2vw,727px)]
              hidden md:block"
            clipPath={`polygon(0.375% 94.473%,33.15% 1.335%,98.62% 0.163%,99.671% 5.54%,66.574% 98.677%,0.375% 94.473%)`}
          />

          {/* Slider 4 */}
          <Slider
            images={sliderImages}
            className="absolute
              bottom-[clamp(78px,8.3vw,158px)]
              right-0
              w-[clamp(263px,31.16vw,593px)]
              hidden sm:block"
            clipPath={`polygon(0.505% 96.478%,68.973% 0.705%,127.92% 0%,129.231% 3.358%,65.936% 99.131%,0.505% 96.478%)`}
          />
        </div>

        {/* ================= STATS ================= */}

        <div className="absolute
          bottom-[clamp(28px,3.05vw,58px)]
          right-0
          flex
          max-lg:static
          max-lg:justify-center
          max-lg:py-[30px]">

          <Stat number={20500} label="Projects Done" />
          <Stat number={100500} label="Happy Clients" />
          <Stat number={150500} label="Team Members" />

          <div className="flex items-center gap-[clamp(15px,1.58vw,30px)]
            pl-[clamp(30px,3.42vw,65px)]
            border-l border-white/20 cursor-pointer"
            onClick={() => setOpen(true)}>
            <span>Play Reel</span>
            <PlayButton onClick={() => setOpen(true)} />
          </div>
        </div>
      </section>

      <VideoModal
        open={open}
        onClose={() => setOpen(false)}
        youtubeId="WUB2pSkwN2M"
      />
    </>
  );
}


